CREATE TABLE IF NOT EXISTS "Mold" (id TEXT PRIMARY KEY, "moldCode" TEXT NOT NULL, "productId" TEXT, "steelType" TEXT DEFAULT 'P20', "cycleLife" INTEGER DEFAULT 500000, cavities INTEGER DEFAULT 1, status TEXT DEFAULT 'design', "createdAt" TIMESTAMP DEFAULT NOW(), "updatedAt" TIMESTAMP DEFAULT NOW());
CREATE TABLE IF NOT EXISTS "MaintenanceRecord" (id UUID DEFAULT gen_random_uuid() PRIMARY KEY, "moldId" TEXT NOT NULL REFERENCES "Mold"(id), type TEXT NOT NULL, description TEXT, cost FLOAT DEFAULT 0, "performedAt" TIMESTAMP DEFAULT NOW());
CREATE TABLE IF NOT EXISTS "CNCJob" (id TEXT PRIMARY KEY, "partNumber" TEXT NOT NULL, "machineId" TEXT, "programId" TEXT, "estimatedHours" FLOAT DEFAULT 0, priority INTEGER DEFAULT 1, status TEXT DEFAULT 'scheduled', "updatedAt" TIMESTAMP DEFAULT NOW());
CREATE TABLE IF NOT EXISTS "ProductionRun" (id TEXT PRIMARY KEY, "moldId" TEXT, "machineId" TEXT, "productSku" TEXT, "targetQuantity" INTEGER DEFAULT 0, "producedQuantity" INTEGER DEFAULT 0, "scrapQuantity" INTEGER DEFAULT 0, "defectRate" FLOAT DEFAULT 0, status TEXT DEFAULT 'scheduled', "createdAt" TIMESTAMP DEFAULT NOW(), "updatedAt" TIMESTAMP DEFAULT NOW());
CREATE TABLE IF NOT EXISTS "QualityCheck" (id TEXT PRIMARY KEY, "runId" TEXT NOT NULL REFERENCES "ProductionRun"(id), passed BOOLEAN DEFAULT false, defects TEXT[] DEFAULT '{}', parameters JSONB DEFAULT '{}', "checkedAt" TIMESTAMP DEFAULT NOW());
CREATE TABLE IF NOT EXISTS "PlastisolFormulation" (id TEXT PRIMARY KEY, "formulaCode" TEXT UNIQUE NOT NULL, components JSONB DEFAULT '{}', viscosity FLOAT DEFAULT 0, "gelTemperature" FLOAT DEFAULT 0, "createdAt" TIMESTAMP DEFAULT NOW());
CREATE TABLE IF NOT EXISTS "CuringCycle" (id TEXT PRIMARY KEY, "formulationId" TEXT REFERENCES "PlastisolFormulation"(id), "lineId" TEXT, "targetTemperature" FLOAT DEFAULT 0, "targetDuration" INTEGER DEFAULT 0, "actualTemperature" FLOAT, "actualDuration" INTEGER, status TEXT DEFAULT 'started', "startedAt" TIMESTAMP DEFAULT NOW());
CREATE TABLE IF NOT EXISTS "BOM" (id TEXT PRIMARY KEY, "productId" TEXT NOT NULL UNIQUE, components JSONB DEFAULT '[]');
CREATE TABLE IF NOT EXISTS "Component" (id TEXT PRIMARY KEY, "productId" TEXT NOT NULL, name TEXT NOT NULL, quantity INTEGER DEFAULT 1, "materialSpec" TEXT);
CREATE TABLE IF NOT EXISTS "Revision" (id TEXT PRIMARY KEY, "productId" TEXT NOT NULL, "revisionNumber" TEXT NOT NULL, changes TEXT, status TEXT DEFAULT 'draft', "approvedBy" TEXT, "approvedAt" TIMESTAMP, "createdAt" TIMESTAMP DEFAULT NOW());
CREATE TABLE IF NOT EXISTS "Fulfillment" (id TEXT PRIMARY KEY, "orderId" TEXT NOT NULL UNIQUE, "centerId" TEXT, status TEXT DEFAULT 'pending', "estimatedDays" INTEGER DEFAULT 3, "trackingCode" TEXT, "carrierId" TEXT, "shippedAt" TIMESTAMP);
CREATE TABLE IF NOT EXISTS "Return" (id TEXT PRIMARY KEY, "orderId" TEXT NOT NULL, reason TEXT, items JSONB DEFAULT '{}', status TEXT DEFAULT 'requested', "createdAt" TIMESTAMP DEFAULT NOW());
CREATE TABLE IF NOT EXISTS "ChannelListing" (id TEXT PRIMARY KEY, "productId" TEXT NOT NULL, channel TEXT NOT NULL, "mlItemId" TEXT, "shopeeItemId" TEXT, price FLOAT, stock INTEGER, status TEXT DEFAULT 'active', "syncedAt" TIMESTAMP DEFAULT NOW(), UNIQUE("productId", channel));
CREATE TABLE IF NOT EXISTS "Store" (id TEXT PRIMARY KEY, name TEXT, address JSONB, "openingHours" JSONB, active BOOLEAN DEFAULT true);
CREATE TABLE IF NOT EXISTS "SaleTransaction" (id TEXT PRIMARY KEY, "storeId" TEXT REFERENCES "Store"(id), total FLOAT DEFAULT 0, "paymentMethod" TEXT, items JSONB DEFAULT '[]', "createdAt" TIMESTAMP DEFAULT NOW());
CREATE TABLE IF NOT EXISTS "ChatOrder" (id TEXT PRIMARY KEY, "chatId" TEXT, "customerId" TEXT, status TEXT DEFAULT 'open', items JSONB DEFAULT '[]', total FLOAT DEFAULT 0, "createdAt" TIMESTAMP DEFAULT NOW());
CREATE TABLE IF NOT EXISTS "ChatSession" (id TEXT PRIMARY KEY, "chatId" TEXT, "customerId" TEXT, status TEXT DEFAULT 'active', messages JSONB DEFAULT '[]', "lastActivity" TIMESTAMP DEFAULT NOW());
CREATE TABLE IF NOT EXISTS "Shipment" (id TEXT PRIMARY KEY, "orderId" TEXT NOT NULL, "carrierId" TEXT, "trackingCode" TEXT, cost FLOAT DEFAULT 0, "estimatedDays" INTEGER DEFAULT 3, status TEXT DEFAULT 'label_created', "createdAt" TIMESTAMP DEFAULT NOW());
CREATE TABLE IF NOT EXISTS "Report" (id TEXT PRIMARY KEY, title TEXT, "metricType" TEXT, data JSONB DEFAULT '{}', period TEXT, "generatedAt" TIMESTAMP DEFAULT NOW());
CREATE TABLE IF NOT EXISTS "Metric" (id TEXT PRIMARY KEY, name TEXT, value FLOAT DEFAULT 0, tags JSONB DEFAULT '{}', "recordedAt" TIMESTAMP DEFAULT NOW());
CREATE TABLE IF NOT EXISTS "Insight" (id TEXT PRIMARY KEY, title TEXT, description TEXT, "confidenceScore" FLOAT DEFAULT 0, "sourceEvents" TEXT[], "generatedAt" TIMESTAMP DEFAULT NOW());
CREATE TABLE IF NOT EXISTS "Agent" (id TEXT PRIMARY KEY, name TEXT NOT NULL, role TEXT, context TEXT, status TEXT DEFAULT 'idle', "systemPrompt" TEXT DEFAULT '', "modelProvider" TEXT DEFAULT 'openai', "modelName" TEXT DEFAULT 'gpt-4o-mini', temperature FLOAT DEFAULT 0.3, "maxTokens" INTEGER DEFAULT 4096, "startedAt" TIMESTAMP, "createdAt" TIMESTAMP DEFAULT NOW(), "updatedAt" TIMESTAMP DEFAULT NOW());
CREATE TABLE IF NOT EXISTS "Workflow" (id TEXT PRIMARY KEY, name TEXT, steps JSONB DEFAULT '[]', status TEXT DEFAULT 'running', "onError" TEXT DEFAULT 'stop', "maxRetries" INTEGER DEFAULT 3, "startedAt" TIMESTAMP DEFAULT NOW(), "completedAt" TIMESTAMP);
CREATE TABLE IF NOT EXISTS "WorkflowExecution" (id UUID DEFAULT gen_random_uuid() PRIMARY KEY, "workflowId" TEXT REFERENCES "Workflow"(id), "stepId" TEXT, "agentId" TEXT, status TEXT DEFAULT 'pending', input JSONB DEFAULT '{}', output JSONB, error TEXT, "startedAt" TIMESTAMP, "completedAt" TIMESTAMP);
CREATE TABLE IF NOT EXISTS "AuditTrail" (id UUID DEFAULT gen_random_uuid() PRIMARY KEY, "agentId" TEXT, action TEXT, input JSONB, output JSONB, error TEXT, duration INTEGER DEFAULT 0, timestamp TIMESTAMP DEFAULT NOW());
